[
  {
    "id": "conflict-001",
    "title": "设备产能是否达到合同约定标准",
    "description": "合同约定稳定产能为6000瓶/小时，首次测试（2026年3月20日）平均产能为5200瓶/小时，复测（2026年3月25日）平均产能为5700瓶/小时，两次均未达标。海川食品认为设备本身存在质量与性能问题；华东智能装备认为未达产系买方提供的瓶体规格不稳定、原料黏度问题及现场电压波动所致",
    "actorIds": ["actor-001", "actor-002"]
  },
  {
    "id": "conflict-002",
    "title": "未达产原因归属存在分歧",
    "description": "海川食品主张系设备本身的质量和性能缺陷导致两次测试均未达到6000瓶/小时；华东智能装备主张卡瓶及产能不足系买方瓶体规格、原料黏度及供电条件不稳定造成，并已在首次测试记录上作此备注",
    "actorIds": ["actor-001", "actor-002"]
  },
  {
    "id": "conflict-003",
    "title": "整改措施及效果认定分歧",
    "description": "华东智能装备于2026年3月22日进行参数调整并更换部分导轨，复测产能由5200瓶/小时提升至5700瓶/小时，但仍低于合同标准。华东智能装备主张已履行整改义务，海川食品认为整改效果仍未达标，设备本质问题未解决",
    "actorIds": ["actor-001", "actor-002"]
  },
  {
    "id": "conflict-004",
    "title": "设备是否通过验收的分歧",
    "description": "海川食品以连续两次测试均未达到合同约定6000瓶/小时为由，明确表示不同意验收；华东智能装备认为设备已完成交付、安装及调试，且已配合整改，应视为已完成验收义务",
    "actorIds": ["actor-001", "actor-002"]
  },
  {
    "id": "conflict-005",
    "title": "12万元尾款支付条件是否成就的分歧",
    "description": "海川食品以设备未通过验收为由暂缓支付验收尾款12万元；华东智能装备认为已按约交付并完成调试，验收尾款支付条件已成就，要求买方支付该12万元尾款",
    "actorIds": ["actor-001", "actor-002"]
  },
  {
    "id": "conflict-006",
    "title": "设备交付迟延3日的责任认定分歧",
    "description": "合同约定交付日期为2026年3月15日，实际物流签收交付日期为2026年3月18日，迟延3日。双方对此事实无异议，但对于是否构成违约及违约责任承担（违约金、损害赔偿等）依据合同条款如何适用存在分歧",
    "actorIds": ["actor-001", "actor-002"]
  }
]

